        }

        .cover-image {
          position: relative;
          height: 250px;
          overflow: hidden;
        }

        .cover-image img {
          width: 100%;
          height: 100%;
          object-fit: cover;
        }

        .avatar-section {
          position: relative;
          display: flex;
          justify-content: center;
