          margin-bottom: 20px;
        }

        .button-group {
          display: flex;
          gap: 15px;
          justify-content: center;
          flex-wrap: wrap;
        }

        .edit-btn {
          background: linear-gradient(135deg, #667eea, #764ba2);
          border: none;
          padding: 10px 20px;
          border-radius: 8px;
          color: white;
          cursor: pointer;
          font-size: 14px;
          transition: all 0.3s;
        }

        .edit-btn:hover {
          transform: scale(1.05);
          box-shadow: 0 0 15px rgba(102,126,234,0.5);
        }

        .logout-btn {
          background: linear-gradient(135deg, #ef4444, #dc2626);
