        .restaurants-header {
          display: flex;
          justify-content: space-between;
          align-items: center;
          margin-bottom: 20px;
          flex-wrap: wrap;
          gap: 15px;
        }

        .restaurants-header h3 {
          color: white;
          font-size: 20px;
        }

        .restaurants-grid {
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(350px, 1fr));
          gap: 20px;
        }

        .no-restaurants {
          text-align: center;
          padding: 50px;
          color: rgba(255,255,255,0.6);
        }

        .stats-grid {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
          gap: 20px;
          margin-bottom: 40px;
        }

        .stat-card {
          background: rgba(0,0,0,0.3);
          padding: 20px;
          border-radius: 12px;
          text-align: center;
          border: 1px solid rgba(255,255,255,0.1);
          transition: all 0.3s;
        }

        .stat-card:hover {
          transform: translateY(-5px);
          border-color: rgba(168,85,247,0.5);
        }

        .stat-card h3 {
          color: rgba(255,255,255,0.7);
          font-size: 14px;
          margin-bottom: 10px;
        }

        .stat-number {
          color: white;
          font-size: 36px;
          font-weight: bold;
        }

        .revenue-details {
          margin-top: 30px;
        }

        .revenue-details h3 {
          color: white;
          margin-bottom: 20px;
        }

        .revenue-table {
          overflow-x: auto;
        }

        .revenue-table table {
          width: 100%;
          border-collapse: collapse;
        }

        .revenue-table th,
        .revenue-table td {
          padding: 12px;
          text-align: left;
          border-bottom: 1px solid rgba(255,255,255,0.1);
          color: rgba(255,255,255,0.8);
        }

        .revenue-table th {
          background: rgba(0,0,0,0.3);
          color: white;
          font-weight: bold;
        }

        .revenue-table tr:hover {
          background: rgba(255,255,255,0.05);
        }

        .messages-section h3 {
          color: white;
          margin-bottom: 20px;
        }

        .messages-list {
          display: flex;
          flex-direction: column;
          gap: 15px;
        }

        .message-card {
          background: rgba(0,0,0,0.3);
          border-radius: 12px;
          padding: 15px;
          border-left: 3px solid #8b5cf6;
          transition: all 0.3s;
        }

        .message-card.unread {
          background: rgba(139, 92, 246, 0.1);
          border-left-color: #f59e0b;
        }

        .message-card:hover {
          transform: translateX(5px);
        }

        .message-header {
          display: flex;
          justify-content: space-between;
          align-items: center;
          margin-bottom: 10px;
          flex-wrap: wrap;
          gap: 10px;
        }

        .message-sender {
          display: flex;
          align-items: center;
          gap: 10px;
        }

        .sender-icon {
          font-size: 20px;
        }

        .message-sender strong {
          color: white;
        }

        .message-date {
          color: rgba(255,255,255,0.5);
          font-size: 12px;
        }

        .unread-badge {
          background: #f59e0b;
          color: white;
          padding: 2px 8px;
          border-radius: 12px;
          font-size: 11px;
        }

        .message-body p {
          color: rgba(255,255,255,0.7);
          line-height: 1.5;
          margin-bottom: 10px;
        }

        .message-actions {
          display: flex;
          gap: 10px;
        }

        .message-actions button {
          background: rgba(255,255,255,0.1);
          border: none;
          padding: 5px 10px;
          border-radius: 6px;
          color: white;
          cursor: pointer;
          font-size: 12px;
          transition: all 0.3s;
        }

        .message-actions button:hover {
          background: rgba(255,255,255,0.2);
        }

        @media (max-width: 768px) {
          .profile-info {
            padding: 15px;
          }
          
          .info-row {
            flex-direction: column;
            gap: 5px;
          }
          
          .restaurants-grid {
            grid-template-columns: 1fr;
          }
          
          .tab-content {
            padding: 20px;
          }
          
          .stats-grid {
            grid-template-columns: 1fr;
          }
          
          .revenue-table th,
          .revenue-table td {
            font-size: 12px;
            padding: 8px;
          }
          
          .button-group {
            flex-direction: column;
            align-items: center;
          }
          
          .edit-btn, .logout-btn {
            width: 200px;
          }
        }
      `}</style>
    </div>
  );
}
